import React, { useState } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft/common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { usePnhPermissions } from '../../../hooks/usePnhPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { purchasingService } from '../../../services/mh/purchasingService';
import { wmsService } from '../../../services/kho/wmsService';
import type { ReceivingNoteLineDto } from '../../../services/mh/models';
import type { PartnerDto } from '../../../services/kho/models';
import { MH_PATHS } from '../../../appPaths';
import { pnhPageLabels } from '../../../constants/pnhPageLabels';
import { DocumentFormHeader } from '../../../components/layout';
import {
  MaterialLinesGridActions,
  useMaterialLinesSelection,
  VoucherDocumentFormShell,
} from '../../../components/form';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import df from '../../../styles/documentForm.module.css';

const emptyLine = (): ReceivingNoteLineDto => ({ purchaseOrderLineId: '', materialCode: '', unitCode: '', quantity: 1, unitPrice: 0, amount: 0 });

const PnhFormPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canWrite } = usePnhPermissions();
  const navigate = useNavigate();
  const { id: routeId } = useParams<{ id: string }>();
  const [searchParams] = useSearchParams();
  const editId = routeId && routeId !== 'them' ? routeId : searchParams.get('editId') ?? undefined;
  const isEdit = Boolean(editId);
  const isNew = !isEdit;
  const [noteDate, setNoteDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [supplierId, setSupplierId] = useState('');
  const [purchaseOrderId, setPurchaseOrderId] = useState('');
  const [warehouseId, setWarehouseId] = useState('');
  const [lines, setLines] = useState<ReceivingNoteLineDto[]>([emptyLine()]);
  const [suppliers, setSuppliers] = useState<PartnerDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const { copyLine, lineRowProps } = useMaterialLinesSelection(lines, setLines);

  const { warehouseOptions } = useVoucherInitData('create-receiving-note');
  React.useEffect(() => {
    let c = false;
    const t = setTimeout(() => {
      wmsService.getPartners('Supplier')
        .then(s => { if (!c) setSuppliers(s); })
        .catch(err => {
          if (!c) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, pnhPageLabels.catalogLoadError),
              type: 'error',
            });
          }
        });
    }, 0);
    return () => { c = true; clearTimeout(t); };
  }, [dispatch]);

  React.useEffect(() => {
    if (!editId) return;
    let c = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getReceivingNote(editId)
        .then(n => {
          if (c) return;
          setNoteDate(n.noteDate?.slice(0, 10) ?? '');
          setSupplierId(n.supplierId);
          setPurchaseOrderId(n.purchaseOrderId);
          setWarehouseId(n.warehouseId);
          setLines(n.lines?.length ? n.lines : [emptyLine()]);
        })
        .catch(err => {
          if (!c) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, pnhPageLabels.formLoadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!c) setLoading(false); });
    }, 0);
    return () => { c = true; clearTimeout(t); };
  }, [editId, dispatch]);

  const supplierOpts = [{ value: '', label: '— NCC —' }, ...suppliers.map(s => ({ value: s.id, label: s.name }))];
  const whOpts = [{ value: '', label: '— Kho —' }, ...warehouseOptions];
  const updateLine = (idx: number, patch: Partial<ReceivingNoteLineDto>) => {
    setLines(prev => prev.map((l, i) => {
      if (i !== idx) return l;
      const next = { ...l, ...patch };
      next.amount = (next.quantity || 0) * (next.unitPrice || 0);
      return next;
    }));
  };
  const addLine = () => setLines(prev => [...prev, emptyLine()]);
  const removeLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: pnhPageLabels.minLineWarning, type: 'warning' });
      return;
    }
    setLines(prev => prev.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    if (!canWrite) return;
    if (!supplierId || !purchaseOrderId || !warehouseId) {
      dispatchAppToast(dispatch, { message: pnhPageLabels.headerWarning, type: 'warning' });
      return;
    }
    setSaving(true);
    try {
      const payload = {
        noteDate: new Date(noteDate).toISOString(),
        supplierId,
        purchaseOrderId,
        warehouseId,
        lines: lines.filter(l => l.materialCode.trim()),
      };
      if (isEdit && editId) {
        await purchasingService.updateReceivingNote(editId, payload);
        dispatchAppToast(dispatch, { message: pnhPageLabels.updateSuccess, type: 'success' });
        navigate(MH_PATHS.nhanHang);
      } else {
        await purchasingService.createReceivingNote(payload);
        dispatchAppToast(dispatch, { message: pnhPageLabels.createSuccess, type: 'success' });
        navigate(MH_PATHS.nhanHang);
      }
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, pnhPageLabels.saveError),
        type: 'error',
      });
    } finally { setSaving(false); }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <VoucherDocumentFormShell
      testId="erp-mh-pnh-form"
      header={(
        <DocumentFormHeader
          onBack={() => navigate(MH_PATHS.nhanHang)}
          title={isEdit ? 'Sửa phiếu nhận' : 'Tạo phiếu nhận'}
          isNew={isNew}
          saving={saving}
          saveLabel="Tạo phiếu"
          saveEditLabel="Lưu thay đổi"
          onSave={canWrite ? handleSave : undefined}
        />
      )}
    >
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin phiếu</h2>
        <div className={df.row4}>
          <div className={df.field}><label className={df.label}>Ngày</label><Input type="date" value={noteDate} onChange={e => setNoteDate(e.target.value)} disabled={!canWrite} /></div>
          <div className={df.field}><label className={df.label}>NCC</label><Select value={supplierId} onChange={e => setSupplierId(e.target.value)} options={supplierOpts} disabled={!canWrite} /></div>
          <div className={df.field}><label className={df.label}>ID đơn MH</label><Input value={purchaseOrderId} onChange={e => setPurchaseOrderId(e.target.value)} disabled={!canWrite} /></div>
          <div className={df.field}><label className={df.label}>Kho</label><Select value={warehouseId} onChange={e => setWarehouseId(e.target.value)} options={whOpts} disabled={!canWrite} /></div>
        </div>
      </div>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết hàng</h2>
        <div className={df.tableWrapper}>
          <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
            <thead><tr><MaterialLineTableHeaders /><th>ĐVT</th><th className={df.thAmount}>SL</th><th className={df.thAmount}>Giá</th><th className={df.thDel} /></tr></thead>
            <tbody>
              {lines.map((line, idx) => (
                <tr key={idx} {...lineRowProps(idx)}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    disabled={!canWrite}
                    onSelect={m => updateLine(idx, {
                      materialCode: m.code,
                      materialName: m.name,
                      unitCode: m.unitCode ?? line.unitCode,
                    })}
                    onClear={() => updateLine(idx, { materialCode: '', materialName: '' })}
                  />
                  <td data-label="ĐVT"><Input value={line.unitCode} onChange={e => updateLine(idx, { unitCode: e.target.value })} disabled={!canWrite} /></td>
                  <td data-label="SL" className={df.tdAmount}><Input type="number" value={String(line.quantity)} onChange={e => updateLine(idx, { quantity: Number(e.target.value) })} disabled={!canWrite} /></td>
                  <td data-label="Giá" className={df.tdAmount}><Input type="number" value={String(line.unitPrice)} onChange={e => updateLine(idx, { unitPrice: Number(e.target.value) })} disabled={!canWrite} /></td>
                  <td className={df.tdDel} data-label="">
                    <button type="button" className={df.btnDeleteLine} onClick={() => removeLine(idx)} title="Xóa dòng" disabled={!canWrite}>×</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <MaterialLinesGridActions
          canEdit={canWrite}
          onAddLine={addLine}
          onCopyLine={copyLine}
          linesCount={lines.length}
        />
      </div>
    </VoucherDocumentFormShell>
  );
};
export default PnhFormPage;
